package com.ichi2.anki.preferences

import androidx.preference.PreferenceCategory
import com.ichi2.anki.R
import com.ichi2.anki.cardviewer.CommandCategory
import com.ichi2.anki.cardviewer.ViewerCommand
import com.ichi2.anki.reviewer.MappableBinding.Companion.toPreferenceString
import com.ichi2.preferences.ControlPreference

class ControlsSettingsFragment : SettingsFragment() {
    override val preferenceResource: Int
        get() = R.xml.preferences_controls
    override val analyticsScreenNameConstant: String
        get() = "prefs.controls"

    override fun initSubscreen() {
        addAllControlPreferencesToScreen()
    }

    /** Attaches all possible [ControlPreference] elements to their respective [PreferenceCategory] */
    fun addAllControlPreferencesToScreen() {
        // Group commands by category and add them to their respective preference categories
        for (command in ViewerCommand.values()) {
            val categoryNameResId = getCategoryNameResId(command.category)
            val category = categoryExists(categoryNameResId).let { exists ->
                if (!exists) {
                    createPreferenceCategory(categoryNameResId)
                } else {
                    findPreference<PreferenceCategory>(getCategoryKey(categoryNameResId))
                }
            }
            val preference = ControlPreference(category.context).apply {
                setTitle(command.resourceId)
                key = command.preferenceKey
                setDefaultValue(command.defaultValue.toPreferenceString())
            }
            category.addPreference(preference)
        }
    }

    /**
     * Check if a preference category with the given resource ID exists
     */
    private fun categoryExists(resourceId: Int): Boolean {
        val key = getCategoryKey(resourceId)
        return findPreference<PreferenceCategory>(key) != null
    }

    /**
     * Create a new preference category with the given title resource ID
     */
    private fun createPreferenceCategory(resourceId: Int): PreferenceCategory {
        val category = PreferenceCategory(context).apply {
            setTitle(resourceId)
            key = getCategoryKey(resourceId)
        }
        preferenceScreen.addPreference(category)
        return category
    }

    /**
     * Get the string resource ID for a command category
     */
    private fun getCategoryNameResId(category: CommandCategory): Int {
        return when (category) {
            CommandCategory.ANSWER_BUTTONS -> R.string.controls_category_answer_buttons
            CommandCategory.FLAGS -> R.string.controls_category_flags
            CommandCategory.WHITEBOARD -> R.string.controls_category_whiteboard
            CommandCategory.CURRENT_CARD_NOTE -> R.string.controls_category_current_card_note
            CommandCategory.NAVIGATION -> R.string.controls_category_navigation
            CommandCategory.MISC -> R.string.controls_category_misc
        }
    }

    /**
     * Get a unique key for a preference category based on its resource ID
     */
    private fun getCategoryKey(resourceId: Int): String {
        return "category_${context.resources.getResourceEntryName(resourceId)}"
    }
}"}

