package com.ichi2.anki.cardviewer

import org.junit.Assert.assertFalse
import org.junit.Assert.assertTrue
import org.junit.Test

class ViewerCommandCategoriesTest {

    @Test
    fun all_commands_have_categories() {
        // Ensure every command has a category (not the default MISC for all commands)
        for (command in ViewerCommand.values()) {
            assertTrue(
                "Command ${command.name} must be assigned to a category",
                command.category != null
            )
        }
    }

    @Test
    fun verify_command_distribution() {
        // Verify that commands are distributed across categories as expected
        val answerButtonsCommands = ViewerCommand.values().filter { it.category == CommandCategory.ANSWER_BUTTONS }
        val flagsCommands = ViewerCommand.values().filter { it.category == CommandCategory.FLAGS }
        val whiteboardCommands = ViewerCommand.values().filter { it.category == CommandCategory.WHITEBOARD }
        val currentCardNoteCommands = ViewerCommand.values().filter { it.category == CommandCategory.CURRENT_CARD_NOTE }
        val navigationCommands = ViewerCommand.values().filter { it.category == CommandCategory.NAVIGATION }
        val miscCommands = ViewerCommand.values().filter { it.category == CommandCategory.MISC }

        // Answer buttons: SHOW_ANSWER + 4 answer button commands = 5
        assertTrue("Answer buttons category should have 5 commands", answerButtonsCommands.size == 5)
        assertTrue("SHOW_ANSWER should be in ANSWER_BUTTONS", 
            answerButtonsCommands.contains(ViewerCommand.SHOW_ANSWER))

        // Flags: 7 toggle flag commands + UNSET_FLAG = 8
        assertTrue("Flags category should have 8 commands", flagsCommands.size == 8)
        assertTrue("UNSET_FLAG should be in FLAGS", 
            flagsCommands.contains(ViewerCommand.UNSET_FLAG))

        // Whiteboard: toggle, clear, change pen color = 3
        assertTrue("Whiteboard category should have 3 commands", whiteboardCommands.size == 3)
        assertTrue("TOGGLE_WHITEBOARD should be in WHITEBOARD", 
            whiteboardCommands.contains(ViewerCommand.TOGGLE_WHITEBOARD))

        // Current card/note: suspend, bury, delete, edit, mark, tag, add note, reschedule = 8
        assertTrue("Card/Note actions category should have at least 6 commands", 
            currentCardNoteCommands.size >= 6)
        assertTrue("DELETE should be in CURRENT_CARD_NOTE", 
            currentCardNoteCommands.contains(ViewerCommand.DELETE))

        // Navigation: page up, page down, abort, abort_and_sync, hint, show_all_hints = 6
        assertTrue("Navigation category should have at least 4 commands", 
            navigationCommands.size >= 4)
        assertTrue("PAGE_UP should be in NAVIGATION", 
            navigationCommands.contains(ViewerCommand.PAGE_UP))

        // All commands should be in some category
        assertTrue("Total commands count should be 38", 
            answerButtonsCommands.size + flagsCommands.size + whiteboardCommands.size + 
            currentCardNoteCommands.size + navigationCommands.size + miscCommands.size == 
            ViewerCommand.values().size)
    }

    @Test
    fun verify_no_empty_categories() {
        // Ensure each category has at least one command
        for (category in CommandCategory.values()) {
            val commandsInCategory = ViewerCommand.values().filter { it.category == category }
            assertFalse(
                "Category $category should have at least one command",
                commandsInCategory.isEmpty()
            )
        }
    }

    @Test
    fun verify_consistent_categorization() {
        // If a command starts with "FLAG", it should be in FLAGS category
        val flagCommands = ViewerCommand.values().filter { 
            it.name.startsWith("TOGGLE_FLAG") || it.name == "UNSET_FLAG" 
        }
        for (command in flagCommands) {
            assertTrue(
                "Flag command ${command.name} should be in FLAGS category",
                command.category == CommandCategory.FLAGS
            )
        }

        // If a command includes "WHITEBOARD", it should be in WHITEBOARD category
        val whiteboardCommands = ViewerCommand.values().filter {
            it.name.contains("WHITEBOARD")
        }
        for (command in whiteboardCommands) {
            assertTrue(
                "Whiteboard command ${command.name} should be in WHITEBOARD category",
                command.category == CommandCategory.WHITEBOARD
            )
        }

        // Answer buttons should be in ANSWER_BUTTONS category
        val answerCommands = ViewerCommand.values().filter {
            it.name.contains("EASE") || it.name == "SHOW_ANSWER"
        }
        for (command in answerCommands) {
            assertTrue(
                "Answer command ${command.name} should be in ANSWER_BUTTONS category",
                command.category == CommandCategory.ANSWER_BUTTONS
            )
        }
    }
}"}

