package com.ichi2.anki.cardviewer

import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.RobolectricTest
import org.junit.Assert.assertTrue
import org.junit.Test
import org.junit.runner.RunWith

/**
 * Test to verify that the answer comparison shows correctly when Type Answer is enabled.
 * 
 * This test ensures that when a user types an answer and then clicks "Show Answer",
 * their typed answer is captured and compared with the correct answer to show
 * the proper comparison (with color coding for correct/incorrect parts).
 */
@RunWith(AndroidJUnit4::class)
class TypeAnswerComparisonTest : RobolectricTest() {

    @Test
    fun testComparisonWithInputTag() {
        // Create TypeAnswer with useInputTag = true (typing in WebView)
        val typeAnswer = TypeAnswer(
            useInputTag = true,
            doNotUseCodeFormatting = false,
            autoFocus = true
        )

        // Set the correct answer
        typeAnswer.correct = "hello world"

        // Simulate user typing an answer
        typeAnswer.input = "hello world"

        // Generate the answer HTML with comparison
        val answerHtml = """[[type:Back]]"""
        val result = typeAnswer.filterAnswer(answerHtml)

        // Verify that the result contains comparison HTML
        // When user types correct answer, it should include typeGood class
        assertTrue(
            "FilterAnswer with useInputTag should generate comparison HTML",
            result.contains("<code") || result.contains("<span")
        )
    }

    @Test
    fun testComparisonWithoutInputTag() {
        // Create TypeAnswer with useInputTag = false (typing in native EditText)
        val typeAnswer = TypeAnswer(
            useInputTag = false,
            doNotUseCodeFormatting = false,
            autoFocus = true
        )

        // Set the correct answer
        typeAnswer.correct = "hello world"

        // Simulate user typing an answer
        typeAnswer.input = "hello world"

        // Generate the answer HTML with comparison
        val answerHtml = """[[type:Back]]"""
        val result = typeAnswer.filterAnswer(answerHtml)

        // Verify that the result contains comparison HTML
        assertTrue(
            "FilterAnswer without useInputTag should generate comparison HTML",
            result.contains("<code") || result.contains("<span")
        )
    }

    @Test
    fun testComparisonWithPartialCorrectAnswer() {
        val typeAnswer = TypeAnswer(
            useInputTag = true,
            doNotUseCodeFormatting = false,
            autoFocus = true
        )

        // Set the correct answer
        typeAnswer.correct = "hello world"

        // Simulate user typing a partially correct answer
        typeAnswer.input = "hello"

        // Generate the answer HTML
        val answerHtml = """[[type:Back]]"""
        val result = typeAnswer.filterAnswer(answerHtml)

        // Verify that the result contains comparison HTML
        assertTrue(
            "FilterAnswer should show comparison for partially correct answer",
            result.contains("<code") || result.contains("<span")
        )
    }

    @Test
    fun testComparisonWithEmptyInput() {
        val typeAnswer = TypeAnswer(
            useInputTag = true,
            doNotUseCodeFormatting = false,
            autoFocus = true
        )

        // Set the correct answer
        typeAnswer.correct = "hello world"

        // User didn't type anything
        typeAnswer.input = ""

        // Generate the answer HTML
        val answerHtml = """[[type:Back]]"""
        val result = typeAnswer.filterAnswer(answerHtml)

        // Verify that the answer is shown
        assertTrue(
            "FilterAnswer should show the correct answer even with empty input",
            result.contains("hello world")
        )
    }
}"}

