package com.ichi2.anki

import androidx.fragment.app.FragmentActivity
import anki.collection.OpChangesAfterUndo
import com.google.android.material.snackbar.Snackbar
import com.ichi2.anki.CollectionManager.TR
import com.ichi2.anki.snackbar.showSnackbar
import com.ichi2.libanki.redo
import com.ichi2.libanki.redoAvailable
import com.ichi2.libanki.undo
import com.ichi2.libanki.undoableOp

/** If there's an action pending in the review queue, undo it and show a snackbar */
suspend fun FragmentActivity.undoAndShowSnackbar(duration: Int = Snackbar.LENGTH_SHORT) {
    withProgress {
        val changes = undoableOp {
            if (!undoAvailable()) {
                OpChangesAfterUndo.getDefaultInstance()
            } else {
                undo()
            }
        }
        val message = if (changes.operation.isEmpty()) {
            TR.actionsNothingToUndo()
        } else {
            TR.undoActionUndone(changes.operation)
        }
        showSnackbar(message, duration)
    }
}

/** If there's an action available to redo, redo it and show a snackbar */
suspend fun FragmentActivity.redoAndShowSnackbar(duration: Int = Snackbar.LENGTH_SHORT) {
    withProgress {
        val changes = undoableOp {
            if (!redoAvailable()) {
                OpChangesAfterUndo.getDefaultInstance()
            } else {
                redo()
            }
        }
        val message = if (changes.operation.isEmpty()) {
            // Fallback: use general redo message if specific one not available
            try {
                TR.actionsNothingToRedo()
            } catch (e: Exception) {
                TR.actionsNothingToUndo() // Fallback to undo message if redo not yet translated
            }
        } else {
            try {
                TR.redoActionRedone(changes.operation)
            } catch (e: Exception) {
                TR.undoActionUndone(changes.operation) // Fallback to undo message if redo not yet translated
            }
        }
        showSnackbar(message, duration)
    }
}"}

